  1→import React, { useState, useEffect } from 'react';
  2→import { AnalysisResult, User, SMCContent } from '../types';
  3→import { generateOptimizedRobotsTxt, generateRobotsWithAI, parseCurrentRobotsTxt, getDetectedPlatformName } from '../services/robots_service';
  4→import { ArrowLeft, FileCode, Download, Copy, Check, Bot, ShieldCheck, AlertTriangle, RefreshCw, ChevronDown, History, Server, Eye, Settings, FileJson, Globe, Terminal, Lock, Zap, Archive, Sparkles, Loader2 } from 'lucide-react';
  5→
  6→interface Props {
  7→  onBack: () => void;
  8→  history: AnalysisResult[];
  9→  user: User | null;
 10→  onDeductCredits: (amount: number) => boolean;
 11→  onUpdateAnalysis: (index: number, data: Partial<AnalysisResult>) => void;
 12→  savedFiles: SMCContent[];
 13→  onSaveFile: (item: SMCContent) => void;
 14→}
 15→
 16→const RobotsTxt: React.FC<Props> = ({ onBack, history, user, onDeductCredits, onUpdateAnalysis, savedFiles, onSaveFile }) => {
 17→  const [selectedAnalysisIndex, setSelectedAnalysisIndex] = useState<number>(0);
 18→  const [currentContent, setCurrentContent] = useState('');
 19→  const [optimizedContent, setOptimizedContent] = useState('');
 20→  const [platformName, setPlatformName] = useState('');
 21→  const [copied, setCopied] = useState(false);
 22→  const [isUnlocked, setIsUnlocked] = useState(false);
 23→  const [isGeneratingAI, setIsGeneratingAI] = useState(false);
 24→
 25→  const GENERATION_COST = 10;
 26→  const AI_GENERATION_COST = 15;
 27→
 28→  // Initialize with data from history
 29→  useEffect(() => {
 30→    const processUrl = (analysis: AnalysisResult | undefined) => {
 31→        if (!analysis) {
 32→            // Mode Demo / Fallback
 33→            const demoUrl = "https://monsite-wordpress.com";
 34→            setCurrentContent(parseCurrentRobotsTxt(demoUrl));
 35→            setOptimizedContent(generateOptimizedRobotsTxt(demoUrl));
 36→            setPlatformName(getDetectedPlatformName(demoUrl));
 37→            setIsUnlocked(false);
 38→            return;
 39→        }
 40→
 41→        const url = analysis.url;
 42→        setCurrentContent(parseCurrentRobotsTxt(url));
 43→        setPlatformName(getDetectedPlatformName(url));
 44→
 45→        // Check if previously unlocked/saved in history
 46→        if (analysis.robotsTxtData && analysis.robotsTxtData.isUnlocked) {
 47→            setOptimizedContent(analysis.robotsTxtData.content);
 48→            setIsUnlocked(true);
 49→        } else {
 50→            // Fresh generation (locked)
 51→            setOptimizedContent(generateOptimizedRobotsTxt(url));
 52→            setIsUnlocked(false);
 53→        }
 54→    };
 55→
 56→    if (history.length > 0) {
 57→      processUrl(history[selectedAnalysisIndex]);
 58→    } else {
 59→      processUrl(undefined);
 60→    }
 61→  }, [selectedAnalysisIndex, history]);
 62→
 63→  const handleUnlock = () => {
 64→    if (onDeductCredits(GENERATION_COST)) {
 65→        setIsUnlocked(true);
 66→
 67→        if (history.length > 0) {
 68→            onUpdateAnalysis(selectedAnalysisIndex, {
 69→                robotsTxtData: {
 70→                    content: optimizedContent,
 71→                    isUnlocked: true,
 72→                    platform: platformName,
 73→                    generatedAt: new Date().toISOString()
 74→                }
 75→            });
 76→        }
 77→
 78→        onSaveFile({
 79→            id: `robots_${Date.now()}`,
 80→            type: 'fiche',
 81→            title: `Robots.txt - ${history[selectedAnalysisIndex]?.url || 'Demo'}`,
 82→            content: optimizedContent,
 83→            timestamp: new Date().toISOString()
 84→        });
 85→    }
 86→  };
 87→
 88→  const handleUnlockAI = async () => {
 89→    if (!onDeductCredits(AI_GENERATION_COST)) return;
 90→
 91→    // Check for pre-generated cache first
 92→    const cachedRobots = history.length > 0 && selectedAnalysisIndex === 0
 93→      ? history[0]?.preGenerated?.robotsTxt
 94→      : undefined;
 95→
 96→    if (cachedRobots?.content) {
 97→      setOptimizedContent(cachedRobots.content);
 98→      setPlatformName(cachedRobots.platformDetected);
 99→      setIsUnlocked(true);
100→
101→      if (history.length > 0) {
102→        onUpdateAnalysis(selectedAnalysisIndex, {
103→          robotsTxtData: {
104→            content: cachedRobots.content,
105→            isUnlocked: true,
106→            platform: cachedRobots.platformDetected,
107→            generatedAt: new Date().toISOString()
108→          }
109→        });
110→      }
111→
112→      onSaveFile({
113→        id: `robots_ai_${Date.now()}`,
114→        type: 'fiche',
115→        title: `Robots.txt (AI) - ${history[selectedAnalysisIndex]?.url || 'Demo'}`,
116→        content: cachedRobots.content,
117→        timestamp: new Date().toISOString()
118→      });
119→      return;
120→    }
121→
122→    setIsGeneratingAI(true);
123→    try {
124→      const url = history.length > 0 ? history[selectedAnalysisIndex].url : 'https://monsite-wordpress.com';
125→      const result = await generateRobotsWithAI(url);
126→      setOptimizedContent(result.content);
127→      setPlatformName(result.platformDetected);
128→      setIsUnlocked(true);
129→
130→      if (history.length > 0) {
131→        onUpdateAnalysis(selectedAnalysisIndex, {
132→          robotsTxtData: {
133→            content: result.content,
134→            isUnlocked: true,
135→            platform: result.platformDetected,
136→            generatedAt: new Date().toISOString()
137→          }
138→        });
139→      }
140→
141→      onSaveFile({
142→        id: `robots_ai_${Date.now()}`,
143→        type: 'fiche',
144→        title: `Robots.txt (AI) - ${history[selectedAnalysisIndex]?.url || 'Demo'}`,
145→        content: result.content,
146→        timestamp: new Date().toISOString()
147→      });
148→    } catch {
149→      // Fallback to local generation
150→      setIsUnlocked(true);
151→    } finally {
152→      setIsGeneratingAI(false);
153→    }
154→  };
155→
156→  const handleDownload = (filename?: string, content?: string) => {
157→    const blob = new Blob([content || optimizedContent], { type: 'text/plain' });
158→    const url = URL.createObjectURL(blob);
159→    const a = document.createElement('a');
160→    a.href = url;
161→    a.download = filename || 'robots.txt';
162→    document.body.appendChild(a);
163→    a.click();
164→    document.body.removeChild(a);
165→    URL.revokeObjectURL(url);
166→  };
167→
168→  const handleCopy = (content?: string) => {
169→    navigator.clipboard.writeText(content || optimizedContent);
170→    setCopied(true);
171→    setTimeout(() => setCopied(false), 2000);
172→  };
173→
174→  const getImplementationSteps = (platform: string) => {
175→    if (platform.includes('WordPress')) {
176→      return {
177→        title: "Installation sur WordPress",
178→        icon: <Settings size={20} />,
179→        steps: [
180→          "Connectez-vous à votre tableau de bord WordPress (/wp-admin).",
181→          "Si vous utilisez Yoast SEO : Allez dans 'SEO' → 'Outils' → 'Éditeur de fichiers'.",
182→          "Si vous utilisez RankMath : Allez dans 'Rank Math' → 'Réglages généraux' → 'Modifier robots.txt'.",
183→          "Si aucun plugin SEO : Utilisez un plugin 'File Manager' ou un accès FTP.",
184→          "Copiez le code généré ci-dessus et remplacez tout le contenu existant.",
185→          "Sauvegardez les modifications."
186→        ]
187→      };
188→    }
