  1→import React, { useState, useEffect } from 'react';
  2→import { AnalysisResult, User, SMCContent } from '../types';
  3→import { generateJsonLd, generateSchemaWithAI, SchemaInput } from '../services/schema_service';
  4→import { ArrowLeft, Code, Download, Copy, Check, ShieldCheck, Globe, Share2, Building2, Phone, Mail, Image as ImageIcon, ExternalLink, RefreshCw, Zap, Archive, Eye, Sparkles, Loader2 } from 'lucide-react';
  5→
  6→interface Props {
  7→  onBack: () => void;
  8→  history: AnalysisResult[];
  9→  user: User | null;
 10→  onDeductCredits: (amount: number) => boolean;
 11→  savedFiles: SMCContent[];
 12→  onSaveFile: (item: SMCContent) => void;
 13→}
 14→
 15→const SchemaOrg: React.FC<Props> = ({ onBack, history, user, onDeductCredits, savedFiles, onSaveFile }) => {
 16→  const [copied, setCopied] = useState(false);
 17→  const [formData, setFormData] = useState<SchemaInput>({
 18→    name: '',
 19→    url: '',
 20→    logoUrl: '',
 21→    description: '',
 22→    socialProfiles: ['', '', ''],
 23→    contactPhone: '',
 24→    contactEmail: '',
 25→    alternateName: ''
 26→  });
 27→  
 28→  const [jsonOutput, setJsonOutput] = useState('');
 29→  const [isGenerated, setIsGenerated] = useState(false);
 30→  const [isGeneratingAI, setIsGeneratingAI] = useState(false);
 31→  const [generationMode, setGenerationMode] = useState<'local' | 'ai'>('local');
 32→
 33→  // Pré-remplissage basé sur l'historique
 34→  useEffect(() => {
 35→    if (history.length > 0) {
 36→      const latest = history[0];
 37→      const urlObj = new URL(latest.url);
 38→      const hostname = urlObj.hostname;
 39→      const name = hostname.replace('www.', '').split('.')[0];
 40→      const formattedName = name.charAt(0).toUpperCase() + name.slice(1);
 41→
 42→      setFormData(prev => ({
 43→        ...prev,
 44→        name: formattedName,
 45→        url: urlObj.origin,
 46→        logoUrl: `${urlObj.origin}/logo.png`,
 47→        description: `Site officiel de ${formattedName}.`,
 48→        contactEmail: `contact@${hostname}`
 49→      }));
 50→    }
 51→  }, [history]);
 52→
 53→  // Régénération automatique à chaque changement du formulaire
 54→  useEffect(() => {
 55→    if (isGenerated) {
 56→        setJsonOutput(generateJsonLd(formData));
 57→    }
 58→  }, [formData, isGenerated]);
 59→
 60→  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
 61→    setFormData({ ...formData, [e.target.name]: e.target.value });
 62→  };
 63→
 64→  const handleSocialChange = (index: number, value: string) => {
 65→    const newSocials = [...formData.socialProfiles];
 66→    newSocials[index] = value;
 67→    setFormData({ ...formData, socialProfiles: newSocials });
 68→  };
 69→
 70→  const handleGenerate = async (mode: 'local' | 'ai' = 'local') => {
 71→    const cost = mode === 'ai' ? 8 : 5;
 72→    if (!onDeductCredits(cost)) return;
 73→
 74→    setGenerationMode(mode);
 75→
 76→    if (mode === 'ai') {
 77→      // Check pre-generated cache first (only if form hasn't been significantly modified from defaults)
 78→      const cachedSchema = history.length > 0 ? history[0]?.preGenerated?.schemaOrg : undefined;
 79→      if (cachedSchema?.content) {
 80→        setJsonOutput(cachedSchema.content);
 81→        setIsGenerated(true);
 82→        onSaveFile({
 83→          id: `schema_ai_${Date.now()}`,
 84→          type: 'fiche',
 85→          title: `Schema Organization (AI) - ${formData.name}`,
 86→          content: cachedSchema.content,
 87→          timestamp: new Date().toISOString()
 88→        });
 89→        return;
 90→      }
 91→
 92→      setIsGeneratingAI(true);
 93→      try {
 94→        const result = await generateSchemaWithAI(formData);
 95→        setJsonOutput(result.content);
 96→        setIsGenerated(true);
 97→        onSaveFile({
 98→          id: `schema_ai_${Date.now()}`,
 99→          type: 'fiche',
100→          title: `Schema Organization (AI) - ${formData.name}`,
101→          content: result.content,
102→          timestamp: new Date().toISOString()
103→        });
104→      } catch {
105→        // Fallback to local on error
106→        const output = generateJsonLd(formData);
107→        setJsonOutput(output);
108→        setIsGenerated(true);
109→      } finally {
110→        setIsGeneratingAI(false);
111→      }
112→    } else {
113→      const output = generateJsonLd(formData);
