  1→import React, { useState, useMemo, useCallback, useEffect } from 'react';
  2→import { AnalysisResult, Recommendation, GeneratedSolution, User } from '../types';
  3→import { generateSolution } from '../services/generator';
  4→import RecommendationCard from '../components/RecommendationCard';
  5→import GenerationModal from '../components/GenerationModal';
  6→import ScoreRing from '../components/ScoreRing';
  7→import EngineBreakdown from '../components/EngineBreakdown';
  8→import { mapAnalysisResults, CRITERIA_LABELS } from '../lib/criteria-mapper';
  9→import { calculateEngineScores, calculateProjectedScores, getMostImpactedEngines } from '../lib/engine-score-calculator';
 10→import { ENGINE_PROFILES } from '../config/engine-weights';
 11→import { Zap, AlertTriangle, Fuel, ArrowRight, ArrowUp, CheckSquare, Square, TrendingUp, Lock, Package } from 'lucide-react';
 12→
 13→// Vault system — Generate All, Reveal on Credit
 14→import { getContentBlocks, getVaultSummary, unlockContent, unlockAll, hasVault } from '../services/solution-vault';
 15→import type { ContentBlock, VaultSummary } from '../services/solution-vault';
 16→import LockedContentCard from '../components/LockedContentCard';
 17→import UnlockAllBanner from '../components/UnlockAllBanner';
 18→
 19→interface Props {
 20→  data: AnalysisResult;
 21→  user: User | null;
 22→  onDeductCredits: (amount: number) => boolean;
 23→  onSaveSolution: (analysisId: string, recId: string, solution: GeneratedSolution) => void;
 24→  onNavigateToAnalysis: () => void;
 25→  onNavigateToRecharge: () => void;
 26→}
 27→
 28→const ActionPlan: React.FC<Props> = ({ data, user, onDeductCredits, onSaveSolution, onNavigateToAnalysis, onNavigateToRecharge }) => {
 29→  // Generation Modal State
 30→  const [isModalOpen, setIsModalOpen] = useState(false);
 31→  const [isGeneratingSolution, setIsGeneratingSolution] = useState(false);
 32→  const [generatedSolution, setGeneratedSolution] = useState<GeneratedSolution | null>(null);
 33→
 34→  // Checked recommendations for projected score
 35→  const [checkedIds, setCheckedIds] = useState<Set<string>>(new Set());
 36→
 37→  // ═══ VAULT — Système "Generate All, Reveal on Credit" ═══
 38→  const auditId = data?.timestamp || 'current';
 39→  const [vaultBlocks, setVaultBlocks] = useState<ContentBlock[]>([]);
 40→  const [vaultSummary, setVaultSummary] = useState<VaultSummary | null>(null);
 41→  const [vaultReloadKey, setVaultReloadKey] = useState(0);
 42→
 43→  // Charger les blocs depuis le vault
 44→  useEffect(() => {
 45→    if (!data) return;
 46→    const loadedBlocks = getContentBlocks(auditId);
 47→    setVaultBlocks(loadedBlocks);
 48→    if (loadedBlocks.length > 0) {
 49→      setVaultSummary(getVaultSummary(auditId));
 50→    }
 51→  }, [auditId, data, vaultReloadKey]);
 52→
 53→  // Gérer le déblocage d'un bloc individuel
 54→  const handleUnlockBlock = useCallback((blockId: string) => {
 55→    const success = onDeductCredits(1);
 56→    if (!success) return;
 57→    unlockContent(auditId, blockId);
 58→    setVaultReloadKey(prev => prev + 1);
 59→  }, [auditId, onDeductCredits]);
 60→
 61→  // Gérer le déblocage de tout
 62→  const handleUnlockAll = useCallback(() => {
 63→    const summary = getVaultSummary(auditId);
 64→    if (!summary || summary.lockedBlocks === 0) return;
 65→    const packCost = summary.creditCostToUnlockAll;
 66→    const success = onDeductCredits(packCost);
 67→    if (!success) return;
 68→    unlockAll(auditId);
 69→    setVaultReloadKey(prev => prev + 1);
 70→  }, [auditId, onDeductCredits]);
 71→
 72→  // Fonction utilitaire pour calculer le coût
 73→  const getSolutionCost = (priority: string): number => {
 74→    switch (priority) {
 75→      case 'critical': return 5;
 76→      case 'high': return 4;
 77→      case 'medium': return 3;
 78→      case 'low': return 1;
 79→      default: return 3;
 80→    }
 81→  };
 82→
 83→  // Map analysis results to criteria for engine scoring
 84→  const criteriaResults = useMemo(() => {
 85→    if (!data) return [];
 86→    return mapAnalysisResults(data);
 87→  }, [data]);
 88→
 89→  // Current engine scores
 90→  const currentEngineScores = useMemo(() => {
 91→    return calculateEngineScores(criteriaResults);
 92→  }, [criteriaResults]);
 93→
 94→  // Build the mapping from recommendation IDs to criterion IDs
 95→  const recToCriterionMap = useMemo(() => {
 96→    const map: Record<string, string> = {};
 97→    if (!data) return map;
 98→    data.recommendations.forEach((rec) => {
 99→      // Recommendations use criterion IDs directly in category field
100→      // Try to find a matching failed criterion in the same category
101→      const failedInCategory = criteriaResults.filter(
102→        c => c.category === rec.category && !c.passed
103→      );
104→      if (failedInCategory.length > 0) {
105→        // Match by index within recommendations of same category
106→        const sameCategory = data.recommendations.filter(r => r.category === rec.category);
107→        const indexInCategory = sameCategory.indexOf(rec);
108→        if (failedInCategory[indexInCategory]) {
109→          map[rec.id] = failedInCategory[indexInCategory].id;
110→        } else if (failedInCategory[0]) {
111→          map[rec.id] = failedInCategory[0].id;
112→        }
113→      }
114→    });
115→    return map;
116→  }, [data, criteriaResults]);
117→
118→  // Projected score calculation based on checked items
119→  const projectedData = useMemo(() => {
120→    if (checkedIds.size === 0) {
121→      return null;
122→    }
123→    // Convert checked recommendation IDs to criterion IDs
124→    const fixedCriteriaIds: string[] = [];
125→    checkedIds.forEach((recId) => {
126→      const criterionId = recToCriterionMap[recId];
127→      if (criterionId) {
128→        fixedCriteriaIds.push(criterionId);
129→      }
130→    });
131→    if (fixedCriteriaIds.length === 0) return null;
132→    return calculateProjectedScores(criteriaResults, fixedCriteriaIds);
133→  }, [checkedIds, criteriaResults, recToCriterionMap]);
134→
135→  // Toggle a recommendation's checked state
136→  const toggleChecked = useCallback((recId: string) => {
137→    setCheckedIds(prev => {
138→      const next = new Set(prev);
139→      if (next.has(recId)) {
140→        next.delete(recId);
141→      } else {
142→        next.add(recId);
143→      }
144→      return next;
145→    });
146→  }, []);
147→
148→  // Select/deselect all
149→  const toggleAll = useCallback(() => {
150→    if (!data) return;
151→    if (checkedIds.size === data.recommendations.length) {
152→      setCheckedIds(new Set());
153→    } else {
154→      setCheckedIds(new Set(data.recommendations.map(r => r.id)));
155→    }
156→  }, [data, checkedIds]);
157→
158→  // Calcul du coût total restant
159→  const totalRemainingCost = useMemo(() => {
160→    if (!data) return 0;
161→    return data.recommendations.reduce((acc, rec) => {
162→        if (data.generatedSolutions && data.generatedSolutions[rec.id]) return acc;
163→        return acc + getSolutionCost(rec.priority);
164→    }, 0);
165→  }, [data?.recommendations, data?.generatedSolutions]);
166→
167→  const handleApplyRecommendation = async (rec: Recommendation) => {
168→    const cost = getSolutionCost(rec.priority);
169→    const success = onDeductCredits(cost);
170→    if (!success) {
171→      return;
172→    }
173→
174→    setIsModalOpen(true);
175→    setIsGeneratingSolution(true);
176→    setGeneratedSolution(null);
177→
178→    try {
179→      const solution = await generateSolution(rec, data.url);
180→      setGeneratedSolution(solution);
181→      onSaveSolution(data.timestamp, rec.id, solution);
182→    } catch (error) {
183→      console.error("Error generating solution", error);
184→      setGeneratedSolution({
185→        title: "Erreur de génération",
186→        explanation: "Le service d'IA est momentanément indisponible.",
187→        type: 'text',
188→        content: "Veuillez réessayer dans quelques instants.",
189→        implementationSteps: ["Réessayez l'opération"]
190→      });
191→    } finally {
192→      setIsGeneratingSolution(false);
193→    }
194→  };
195→
196→  const handleOpenStoredSolution = (solution: GeneratedSolution) => {
197→    setGeneratedSolution(solution);
198→    setIsModalOpen(true);
199→  };
200→
201→  if (!data) {
202→    return (
203→        <div className="w-full px-4 py-10 min-h-[80vh] flex flex-col items-center justify-center text-center">
204→            <div className="w-20 h-20 bg-white/[0.04] rounded-2xl flex items-center justify-center mb-6">
205→                <Zap size={40} className="text-gray-500" />
206→            </div>
207→            <h2 className="text-2xl font-bold text-white mb-2">Aucun plan d'action actif</h2>
208→            <p className="text-gray-500 max-w-md mb-8">
209→                Veuillez d'abord lancer une analyse ou sélectionner un projet pour générer un plan d'action AEO.
210→            </p>
211→            <button
212→                onClick={onNavigateToAnalysis}
213→                className="px-6 py-3 bg-gradient-to-r from-purple-500 to-violet-600 text-white font-bold rounded-2xl hover:from-purple-600 hover:to-violet-700 transition-colors"
214→            >
215→                Lancer une analyse
216→            </button>
217→        </div>
218→    );
219→  }
