 30→// Helper to convert AnalysisResult to Project format
 31→const mapAnalysisToProject = (analysis: AnalysisResult, index: number): Project => {
 32→  const hostname = new URL(analysis.url).hostname;
 33→  return {
 34→    id: `proj_${index}_${hostname}`,
 35→    name: hostname,
 36→    domain: analysis.url,
 37→    status: 'active',
 38→    lastRun: analysis.timestamp,
 39→    visibilityScore: analysis.globalScore,
 40→    trend: analysis.globalScore > 70 ? 12 : (analysis.globalScore > 50 ? 5 : -5), // Simulé basé sur le score
 41→    nextRun: new Date(new Date(analysis.timestamp).getTime() + 86400000 * 7).toISOString()
 42→  };
 43→};
