 45→const Projects: React.FC<ProjectsProps> = ({ onBack, onNavigateToAnalysis, user, history, onViewAnalysis, projectCount, maxProjects, onNavigateToPlan, onDeductCredits, onSaveSolution, onNewAnalysis, onNavigateToRecharge, initialUrl, initialTab }) => {
 46→  // Navigation internal state: monitoring | report | action-plan | rescan | archives
 47→  const [activeTab, setActiveTab] = useState<'monitoring' | 'report' | 'action-plan' | 'rescan' | 'archives'>(() => {
 48→    if (initialTab === 'archives') return 'archives';
 49→    if (initialTab === 'recommendations' || initialTab === 'action-plan') return 'action-plan';
 50→    if (initialTab === 'details' || initialTab === 'report') return 'report';
 51→    return 'monitoring';
 52→  });
