 86→          nextRun: new Date(Date.now() + 86400000).toISOString()
 87→        }
 88→      ] as Project[];
 89→    }
 90→  }, [history]);
 91→
 92→  const [selectedProjectId, setSelectedProjectId] = useState<string>(() => {
 93→    if (initialUrl && projects.length > 0) {
 94→        try {
 95→            const targetHost = new URL(initialUrl).hostname;
 96→            // The projects mapping uses hostname as name
 97→            const found = projects.find(p => p.name === targetHost);
 98→            if (found) return found.id;
 99→        } catch(e) {}
100→    }
101→    return projects[0]?.id || '';
102→  });
103→
104→  const [selectedAnalysisState, setSelectedAnalysisState] = useState<AnalysisResult | null>(null);
105→  
106→  // States for viewing archive modal
107→  const [isModalOpen, setIsModalOpen] = useState(false);
108→  const [currentSolution, setCurrentSolution] = useState<GeneratedSolution | null>(null);
109→
110→  const currentProject = projects.find(p => p.id === selectedProjectId) || projects[0];
111→  
112→  // Filter history for current project ONLY
113→  const projectHistory = useMemo(() => {
114→    return history
115→      .filter(h => {
116→          try { return new URL(h.url).hostname === currentProject.name; }
117→          catch(e) { return false; }
118→      })
119→      .sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());
120→  }, [history, currentProject]);
